from typing import Any

def is_tool_turn(messages: list[dict]) -> bool:
    """True if the message group contains a tool_use/tool_result exchange."""
    for msg in messages:
        content = msg.get("content", "")
        if isinstance(content, list):
            for block in content:
                if isinstance(block, dict) and block.get("type") in ("tool_use", "tool_result"):
                    return True
    return False

def safe_window_with_tools(
    history: list[dict],
    max_tokens: int = 120_000,
    model: str = "claude-opus-4-8",
) -> list[dict]:
    """Trim history from the front while respecting tool_use/tool_result pairs.

    Never splits a tool exchange. Stops trimming once under max_tokens.
    """
    if count_history_tokens(history, model) <= max_tokens:
        return history

    # Walk pairs: each user msg + following assistant msg = one pair
    result = history[:]
    while len(result) >= 2 and count_history_tokens(result, model) > max_tokens:
        # Check if the first two messages form part of a tool exchange
        pair = result[:2]
        if is_tool_turn(pair):
            # Drop the entire tool exchange (could span multiple messages)
            # Find where the exchange ends (all tool_results answered)
            result = result[2:]
        else:
            result = result[2:]

    # Make sure we start on a user message
    while result and result[0]["role"] != "user":
        result = result[1:]

    return result

def inject_context(
    history: list[dict],
    context_text: str,
    label: str = "Project Context",
) -> list[dict]:
    """Prepend a context block to the history if not already present.

    Idempotent: checks for the label before inserting to avoid duplicates
    when called multiple times in a session.
    """
    marker = f"[{label}]"
    # Check if context is already in history
    for msg in history:
        content = msg.get("content", "")
        if isinstance(content, str) and marker in content:
            return history  # already injected

    context_block = [
        {
            "role": "user",
            "content": f"{marker}\n{context_text}",
        },
        {
            "role": "assistant",
            "content": f"I have read and understood the {label}. Ready to assist.",
        },
    ]
    return context_block + history

